code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int max = 0;
            for (int i = 0; i < N; i++) {
                int x = sc.nextInt();
                if (x > max) max = x;
            }
            if (max == 1) System.out.println(-1);
            else System.out.println(2*N + max - 2);
        }
    }
}

