    const N = parseInt(readline());
    let max = 0;
    const arr = readline().split(' ').map(x => parseInt(x));
    for (let j = 0; j < N; j++) {
        if (arr[j] > max) max = arr[j];
    }
    if (max == 1) console.log(-1);
    else console.log(2*N + max - 2);
